package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;

import com.google.gson.internal.Excluder;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class GsonExcluderTest {

  private Gson gson;

  @BeforeEach
  void setUp() {
    gson = new Gson();
  }

  @Test
  void testExcluder_notNull() {
    Excluder excluder = gson.excluder();
    assertNotNull(excluder, "Excluder should not be null");
  }

  @Test
  void testExcluder_reflectionAccess() throws Exception {
    // Access the final field 'excluder' via reflection and compare to method result
    Field excluderField = Gson.class.getDeclaredField("excluder");
    excluderField.setAccessible(true);
    Excluder fieldValue = (Excluder) excluderField.get(gson);

    Excluder methodValue = gson.excluder();

    assertSame(fieldValue, methodValue, "excluder() should return the same instance as the private field");
  }
}
